    mediaURL: "https://youtu.be/DtnzHxh5x38",
    textURL: "https://victormazzihuaycucho-blogspot-com.translate.goog/2011/04/poesia-quechua-en-guaman-poma-de-ayala.html?_x_tr_sl=es&_x_tr_tl=en&_x_tr_hl=en"
